    return [
      {
        name: `${baseName}-cjs`,
        format: 'cjs' as const,
        bundle: true,
        entryPoints: [entry],
        outfile,
        outExtension: { '.js': '.js' },
        emitTypes: true,
      },
      {
        name: `${baseName}-esm`,
        format: 'esm' as const,
        bundle: true,
        entryPoints: [entry],
        outfile,
        outExtension: { '.js': '.mjs' },
        emitTypes: true,
      },
    ]
  })
}

export const adapterConfig = createAdapterConfig([{ entry: 'src/index.ts', outfile: 'dist/index' }])

