import type * as DMMF from '@prisma/dmmf'

/** Maps a Prisma scalar type name to the corresponding TypeScript type. */
export function scalarToTs(prismaType: string): string {
  switch (prismaType) {
    case 'String':
      return 'string'
    case 'Boolean':
      return 'boolean'
    case 'Int':
    case 'Float':
      return 'number'
    case 'BigInt':
      return 'bigint'
    case 'DateTime':
      return 'Date'
    case 'Json':
      return 'unknown'
    case 'Bytes':
      return 'Uint8Array'
    case 'Decimal':
      return 'string'
    default:
      // Enum or relation model name — pass through as-is.
      return prismaType
  }
}

/**
 * Resolves a DMMF field's TypeScript type, respecting list and nullability
 * modifiers.
 */
export function fieldToTs(field: DMMF.Field): string {
  const base = scalarToTs(field.type)
  const withList = field.isList ? `${base}[]` : base
  return field.isRequired ? withList : `${withList} | null`
}

/** Renders a TypeScript `const enum`-style union from a DMMF enum. */
export function renderEnum(dmmfEnum: DMMF.DatamodelEnum): string {
  const members = dmmfEnum.values.map((v) => `  ${v.name} = '${v.name}',`).join('\n')
  return `export enum ${dmmfEnum.name} {\n${members}\n}`
}

/**
 * Renders the full TypeScript interface representing all fields of a model,
 * including relation fields typed by their target model name.
 */
export function renderModelInterface(model: DMMF.Model): string {
  const fields = model.fields
    .map((f) => {
      const tsType = fieldToTs(f)
      const optional = !f.isRequired ? '?' : ''
      return `  ${f.name}${optional}: ${tsType}`
    })
    .join('\n')
  return `export interface ${model.name} {\n${fields}\n}`
}

/**
 * Renders the `WhereUniqueInput` type, which covers the `@id` field and any
 * `@unique` scalar fields.
 */
export function renderWhereUniqueInput(model: DMMF.Model): string {
  const uniqueFields = model.fields.filter((f) => f.isId || f.isUnique)
  if (uniqueFields.length === 0) {
    return `export type ${model.name}WhereUniqueInput = Record<string, never>`
  }
  const members = uniqueFields
    .map((f) => {
      const tsType = scalarToTs(f.type)
      return `  ${f.name}?: ${tsType}`
    })
    .join('\n')
  return `export type ${model.name}WhereUniqueInput = {\n${members}\n}`
}

