  const writable = model.fields.filter((f) => f.kind === 'scalar' && !f.isReadOnly)
  const members = writable
    .map((f) => {
      const tsType = scalarToTs(f.type)
      const isAutoGenerated = f.hasDefaultValue || f.isUpdatedAt
      const optional = isAutoGenerated || !f.isRequired ? '?' : ''
      return `  ${f.name}${optional}: ${tsType}`
